module synchronous_down_counter(
   input                reset_clk,
   input                rst,
   input                load,
   input                en,
   input      [3:0]     D,

   output reg [3:0]     Q
);
    always @(posedge reset_clk) begin
        if (rst) Q <= 4'd0;
        else if (load) Q <= D;
        else if (en) Q <= Q - 1;
    end
endmodule
